def create_sequences_from_array(values, window):
    X, y = [], []
    v = np.asarray(values).reshape(-1)
    for i in range(len(v) - window):
        X.append(v[i:i+window])
        y.append(v[i+window])
    X = np.array(X, dtype=np.float32)
    y = np.array(y, dtype=np.float32).reshape(-1,1)
    return X, y

